        $attrs[] = 'ariaLabel';
    }
    return $attrs;
} );
add_filter( 'render_block', function( $content, $block ) {
    if ( ( $block['blockName'] ?? '' ) !== 'core/button' ) {
        return $content;
    }
    if ( empty( $block['attrs']['ariaLabel'] ) ) {
        return $content;
    }
    $aria = esc_attr( $block['attrs']['ariaLabel'] );
    // Ensure sanitized aria-label is present even if theme filters markup.
    if ( str_contains( $content, 'aria-label=' ) ) {
        return preg_replace( '/aria-label="[^"]*"/', 'aria-label="' . $aria . '"', $content );
    }
    return str_replace( '<a ', '<a aria-label="' . $aria . '" ', $content );
}, 10, 2 );

function wpbp_count_block_types( string $html ): array {
    $counts     = array();
    $processor  = new WP_Block_Processor( $html );
    while ( $block = $processor->extract_full_block_and_advance() ) {
        $name = $block->block_name;
        if ( ! $name || $name === 'core/freeform' ) {
            continue;
        }
        $counts[ $name ] = ($counts[ $name ] ?? 0) + 1;
        if ( ! empty( $block->inner_html ) ) {
            foreach ( wpbp_count_block_types( $block->inner_html ) as $k => $v ) {
                $counts[ $k ] = ($counts[ $k ] ?? 0) + $v;
            }
        }
    }
    return $counts;
}

function wpbp_first_paragraph_html( string $html ): string {
    $processor = WP_HTML_Processor::create_fragment( $html );
    $capturing = false;
    $depth     = 0;
    $buffer    = '';
    while ( $processor->next_token() ) {
        $type = $processor->get_token_type();
        if ( ! $capturing && 'start tag' === $type && 'p' === $processor->get_tag() ) {
            $capturing = true;
            $depth     = 1;
            $buffer   .= $processor->serialize_token();
            continue;
        }
        if ( ! $capturing ) {
            continue;
        }
        // While capturing, append every token until the matching </p> closes.
        $buffer .= $processor->serialize_token();
        if ( 'start tag' === $type && $processor->get_tag() === 'p' ) {
            $depth++;
        } elseif ( 'end tag' === $type && $processor->get_tag() === 'p' ) {
            $depth--;
            if ( $depth === 0 ) {
                return $buffer;
            }
        }
    }
    return '';
}

