function wpbp_cached_flag(): bool {
    $cached = wp_cache_get( 'flag', 'wpbp-cache-flag', false, $found );
    if ( $found ) {
        return (bool) $cached;
    }
    // Simulate expensive computation that yields false first time.
    $value = false;
    wp_cache_set( 'flag', $value, 'wpbp-cache-flag' );
    return $value;
}

